+
+	graph := NewDependencyGraph(workflow)
+	unreachable := graph.findUnreachable()
+
+	if len(unreachable) != 0 {
+		t.Errorf("expected 0 unreachable steps, got %d: %v", len(unreachable), unreachable)
+	}
+}
