+		t.Errorf("expected 0 total findings, got %d", analysis.TotalFindings)
+	}
+	if len(analysis.HighImpactFindings) != 0 {
+		t.Errorf("expected 0 high impact findings, got %d", len(analysis.HighImpactFindings))
